import { useState } from 'react'
import styled from 'styled-components';

import GlobalStyle from './GlobalStyles';
import LandingPage from './components/LandingPage/'

const App = () => {
  const [hamburgerState, setHamburgerState] = useState(false)

  return (
    <AppContainer>
      <GlobalStyle />

      <LandingPage id="Home" hamburgerState={hamburgerState} setHamburgerState={setHamburgerState} />
      <div id="Projects" style={{ 
        background: "white",
        width: "100%",
        height: "100vh",
        fontSize: "10em"
      }}>
        PROJECTS
      </div>
      <div id="Contact" style={{ 
        background: "white",
        width: "100%",
        height: "100vh",
        fontSize: "10em"
      }}>
        CONTACT
      </div>
    </AppContainer>
  );
}

const AppContainer = styled.div``

export default App;
